% CreateInputFiles_v12_temporary.m
%
% Purpose:
%   Build a temporary no-catch TrialStruct file for the one-dot occlusion
%   paradigm generated by stimuli_generation_v18.m.
%
%   This script creates:
%     input_files/SubXX_TrialStruct.mat
%
%   from:
%     input_files/MovDot_SubXX.mat
%
%   while preserving trial metadata needed to inspect/trace trial identity
%   (condition label, source trial index, sequence ID), and while keeping all
%   catch-related arrays empty.
%
% Why this temporary version exists:
%   - The occlusion runtime (MoveDot1_experiment_occlusion_v1.m) can read
%     MovDot_SubXX.mat directly.
%   - Some workflows still expect a SubXX_TrialStruct.mat artifact.
%   - This script provides a lightweight compatibility artifact without adding
%     catch logic or mutating existing v11 behavior.
%
% Usage example (interactive):
%   cd('/Users/damiano/Documents/UniTn/Dynamo/Attention/DAD/experiment');
%   CreateInputFiles_v12_temporary
%
% Usage example (non-interactive):
%   /Applications/MATLAB_R2020a.app/bin/matlab -batch ...
%   "cd('/Users/damiano/Documents/UniTn/Dynamo/Attention/DAD/experiment'); iSub=70; nRuns=1; randomSeed=70; run('CreateInputFiles_v12_temporary.m');"
%
% Inputs:
%   - input_files/MovDot_SubXX.mat with:
%       * xySeqs
%       * Cfg
%
% Outputs:
%   - input_files/SubXX_TrialStruct.mat with:
%       * TrialStruct  (nRuns x nTrials, no-catch entries)
%       * Catch        (catch parameters all set to no-catch defaults)
%       * TrialOrder   (1 x nTrials x nRuns)
%       * BlockOrder   (nRuns x 1, all ones)
%
% Key assumptions:
%   - Input contains one-dot occlusion labels:
%       always_visible, occluded_nondeviant, occluded_deviant
%   - Trial order is balanced across the three conditions by truncating to
%     the minimum available count per condition.

%% Setup and input collection
% Data flow: user input -> subject/run/seed controls -> source/target filenames.
clearvars -except iSub nRuns randomSeed overwriteExisting;
clc;
addpath('lib/');

if ~(exist('iSub', 'var') && exist('nRuns', 'var') && exist('randomSeed', 'var'))
    prompt = {'Subject Number:', 'Number of runs:', 'Random seed:'};
    dlgtitle = 'CreateInputFiles v12 temporary';
    dims = [1 50];
    definput = {'70', '1', '70'};
    answer = inputdlg(prompt, dlgtitle, dims, definput);
    if isempty(answer)
        disp('Canceled by user.');
        return;
    end
    iSub = str2double(answer{1});
    nRuns = str2double(answer{2});
    randomSeed = str2double(answer{3});
end

if any(isnan([iSub, nRuns, randomSeed]))
    error('Subject, runs, and random seed must be numeric.');
end
iSub = round(iSub);
nRuns = round(nRuns);
randomSeed = round(randomSeed);
if iSub < 0 || nRuns < 1
    error('Subject must be >= 0 and nRuns must be >= 1.');
end

rng(randomSeed);

inputDir = fullfile('.', 'input_files');
inputFile = fullfile(inputDir, sprintf('MovDot_Sub%02d.mat', iSub));
outputFile = fullfile(inputDir, sprintf('Sub%02d_TrialStruct.mat', iSub));

if ~isfile(inputFile)
    error('Input file not found: %s', inputFile);
end
if exist(outputFile, 'file') == 2
    doOverwrite = false;
    if exist('overwriteExisting', 'var') && ~isempty(overwriteExisting)
        doOverwrite = logical(overwriteExisting);
    end
    if ~doOverwrite
        error('Output already exists; refusing overwrite: %s', outputFile);
    end
end

%% Load source trajectories and validate required fields
% Data flow: MovDot_SubXX.mat -> xySeqs struct -> condition-index pools.
Dat = load(inputFile, 'xySeqs', 'Cfg');
if ~isfield(Dat, 'xySeqs') || isempty(Dat.xySeqs)
    error('Input file must contain non-empty xySeqs: %s', inputFile);
end
if ~isfield(Dat, 'Cfg')
    error('Input file must contain Cfg: %s', inputFile);
end

xyAll = Dat.xySeqs(:);
if ~isfield(xyAll, 'xy')
    error('xySeqs entries must contain .xy');
end

labels = strings(numel(xyAll), 1);
if isfield(xyAll, 'condition_label')
    labels = arrayfun(@(s) string(s.condition_label), xyAll, 'UniformOutput', true);
end

idxAlways = find(labels == "always_visible");
idxNondev = find(labels == "occluded_nondeviant");
idxDev = find(labels == "occluded_deviant");

if isempty(idxAlways) || isempty(idxNondev) || isempty(idxDev)
    error(['Expected condition labels always_visible, occluded_nondeviant, and ' ...
        'occluded_deviant in %s.'], inputFile);
end

nPerCond = min([numel(idxAlways), numel(idxNondev), numel(idxDev)]);
if nPerCond < 1
    error('Not enough trials to build balanced occlusion order.');
end
nTrials = nPerCond * 3;

%% Build balanced run orders
% Data flow: condition index pools -> per-run interleaved condition order.
TrialOrder = zeros(1, nTrials, nRuns);
BlockOrder = ones(nRuns, 1); % One logical block in this temporary no-catch format.

for iRun = 1:nRuns
    runOrder = local_build_balanced_order(idxAlways, idxNondev, idxDev, nPerCond);
    TrialOrder(1, :, iRun) = runOrder;
end

%% Build TrialStruct with empty catch arrays and traceable metadata
% Data flow: TrialOrder -> TrialStruct entries with no-catch placeholders.
trialTemplate = struct( ...
    'Type', [], ...
    'Start', [], ...
    'Condition', [], ...
    'PathDuration', [], ...
    'VideoNumber', [], ...
    'Congruence', [], ...
    'IncongruentOffSet', [], ...
    'SimulatedPath', {{}}, ...
    'SimulatedNewAngle', {{}}, ...
    'End', [], ...
    'ConditionLabel', '', ...
    'SourceTrialIndex', [], ...
    'SequenceID', [], ...
    'OcclusionEnabled', false);

TrialStruct = repmat(trialTemplate, nRuns, nTrials);

for iRun = 1:nRuns
    runOrder = TrialOrder(1, :, iRun);
    for iSeq = 1:nTrials
        sourceIdx = runOrder(iSeq);
        sourceTrial = xyAll(sourceIdx);

        TrialStruct(iRun, iSeq).Type = [];
        TrialStruct(iRun, iSeq).Start = [];
        TrialStruct(iRun, iSeq).End = [];
        TrialStruct(iRun, iSeq).Congruence = [];
        TrialStruct(iRun, iSeq).IncongruentOffSet = [];
        TrialStruct(iRun, iSeq).SimulatedPath = cell(0, 1);
        TrialStruct(iRun, iSeq).SimulatedNewAngle = cell(0, 1);

        TrialStruct(iRun, iSeq).Condition = local_condition_code(sourceTrial);
        TrialStruct(iRun, iSeq).ConditionLabel = local_condition_label(sourceTrial);
        TrialStruct(iRun, iSeq).SourceTrialIndex = sourceIdx;
        TrialStruct(iRun, iSeq).SequenceID = local_sequence_id(sourceTrial, sourceIdx);
        TrialStruct(iRun, iSeq).OcclusionEnabled = local_occlusion_enabled(sourceTrial);

        if isfield(sourceTrial, 'pathDuration') && ~isempty(sourceTrial.pathDuration)
            TrialStruct(iRun, iSeq).PathDuration = double(sourceTrial.pathDuration);
        else
            if isfield(Dat.Cfg, 'fps') && Dat.Cfg.fps > 0
                TrialStruct(iRun, iSeq).PathDuration = size(sourceTrial.xy, 1) / double(Dat.Cfg.fps);
            else
                TrialStruct(iRun, iSeq).PathDuration = NaN;
            end
        end

        if isfield(sourceTrial, 'sequence') && ~isempty(sourceTrial.sequence)
            TrialStruct(iRun, iSeq).VideoNumber = double(sourceTrial.sequence);
        else
            TrialStruct(iRun, iSeq).VideoNumber = double(sourceIdx);
        end
    end
end

%% Build no-catch Catch struct
% Data flow: Cfg defaults -> catch timing container with zero active catches.
Catch = struct();
Catch.OcclAngleDisplacement = 0;
Catch.PlacingNewPos = 0;
Catch.MaxOverlap = 0;
Catch.nCatchPerSeq = 0;
Catch.CatchRatioFix = 0;
Catch.CatchStart = 0;
Catch.CatchDistance = 0;
Catch.BouncingEnd = 0;
Catch.FixDuration = 0;
Catch.FixResponseDuration = 0;
Catch.FixWaitingDuration = 0;
Catch.FixTotalDuration = 0;
Catch.OcclDuration = 0;
Catch.OcclVideoDuration = 0;
Catch.OcclResponseDuration = 0;
Catch.OcclWaitingDuration = 0;
Catch.OcclTotalDuration = 0;
Catch.CatchRatioOcc = 0;
Catch.OcclDeviance = 0;
Catch.OcclDistance = 0;
Catch.CatchDuration = [0 0];
if isfield(Dat.Cfg, 'Stimulitype')
    Catch.Stimulitype = Dat.Cfg.Stimulitype;
else
    Catch.Stimulitype = 0;
end
Catch.BouncingStart = 0;
Catch.nCatchPerRun = 0;
Catch.nCatchTotal = 0;

%% Save output
% Data flow: generated structs -> SubXX_TrialStruct.mat compatibility artifact.
save(outputFile, 'TrialStruct', 'Catch', 'TrialOrder', 'BlockOrder');

fprintf('Saved temporary no-catch trial struct: %s\n', outputFile);
fprintf('Subject %02d | runs=%d | trials per run=%d (balanced %d per condition)\n', ...
    iSub, nRuns, nTrials, nPerCond);

%% Local helpers
function runOrder = local_build_balanced_order(idxAlways, idxNondev, idxDev, nPerCond)
% LOCAL_BUILD_BALANCED_ORDER Build interleaved [always, nondev, dev] order.
a = idxAlways(randperm(numel(idxAlways)));
n = idxNondev(randperm(numel(idxNondev)));
d = idxDev(randperm(numel(idxDev)));
a = a(1:nPerCond);
n = n(1:nPerCond);
d = d(1:nPerCond);
runOrder = zeros(1, nPerCond * 3);
for i = 1:nPerCond
    base = (i - 1) * 3;
    runOrder(base + 1) = a(i);
    runOrder(base + 2) = n(i);
    runOrder(base + 3) = d(i);
end
end

function condCode = local_condition_code(trial)
% LOCAL_CONDITION_CODE Map condition label to legacy numeric condition code.
if isfield(trial, 'condition') && ~isempty(trial.condition)
    condCode = double(trial.condition);
    return;
end
label = local_condition_label(trial);
switch label
    case 'always_visible'
        condCode = -1;
    case 'occluded_nondeviant'
        condCode = 0;
    case 'occluded_deviant'
        condCode = 45;
    otherwise
        condCode = NaN;
end
end

function label = local_condition_label(trial)
% LOCAL_CONDITION_LABEL Return lowercase condition label or empty string.
if isfield(trial, 'condition_label') && ~isempty(trial.condition_label)
    label = lower(char(trial.condition_label));
else
    label = '';
end
end

function seqId = local_sequence_id(trial, fallbackIdx)
% LOCAL_SEQUENCE_ID Read source sequence field if present, else fallback index.
if isfield(trial, 'sequence') && ~isempty(trial.sequence)
    seqId = double(trial.sequence);
else
    seqId = double(fallbackIdx);
end
end

function tf = local_occlusion_enabled(trial)
% LOCAL_OCCLUSION_ENABLED Read occlusion_enabled with false fallback.
if isfield(trial, 'occlusion_enabled') && ~isempty(trial.occlusion_enabled)
    tf = logical(trial.occlusion_enabled);
else
    tf = false;
end
end
